document.getElementById("year").textContent=(new Date).getFullYear();const mobileToggle=document.getElementById("mobileToggle"),mainNav=document.getElementById("mainNav");mobileToggle.addEventListener("click",function(){const e=mainNav.classList.toggle("open");mobileToggle.setAttribute("aria-expanded",e)}),mainNav.querySelectorAll("a").forEach(function(e){e.addEventListener("click",function(){mainNav.classList.remove("open"),mobileToggle.setAttribute("aria-expanded","false")})}),document.querySelectorAll(".faq-item").forEach(function(e){const t=e.querySelector(".faq-question");t.addEventListener("click",function(){const l=e.classList.toggle("open");t.setAttribute("aria-expanded",l)})});const galleryItems=document.querySelectorAll(".gallery-item"),galleryModal=document.getElementById("galleryModal"),modalBody=document.getElementById("modalBody"),modalClose=document.getElementById("modalClose");galleryItems.forEach(function(e){e.addEventListener("click",function(){var t=e.querySelector("img"),l=e.getAttribute("data-label")||"";if(modalBody.innerHTML="",t){var a=document.createElement("img");a.src=t.src,a.alt=t.alt,modalBody.appendChild(a)}if(l){var o=document.createElement("div");o.className="modal-label",o.textContent=l,modalBody.appendChild(o)}galleryModal.classList.add("open")})}),modalClose.addEventListener("click",function(){galleryModal.classList.remove("open")}),galleryModal.addEventListener("click",function(e){e.target===galleryModal&&galleryModal.classList.remove("open")});